import assert from 'node:assert/strict';
import { readFile } from 'node:fs/promises';

const output = JSON.parse(await readFile(new URL('../src/quality-output.json', import.meta.url), 'utf8'));
assert.equal(output.ready, true);
assert.equal(output.marker, 'FUNPLAY_NATIVE_QUALITY_OK');
console.log('native-quality-script acceptance passed');
